howItWorks.step1Code:
yourCenturion.understand({
  mission: 'yours',
  privacy: 'absolute',
  home: 'defined',
  leavesHome: false
})

// Entendido – e fica consigo.

howItWorks.step2Code:
yourCenturion.place({
  where: 'your home',
  outsideWorld: 'your choice',
  leaves: false
})

// Assentou. Nada se perde.

howItWorks.step3Code:
yourCenturion.live({
  always: true,
  learns: 'from you only',
  shares: 'nothing',
  companySees: 'nothing'
})

// Privado. Leal. Seu.

developers.code1:
// As skills de outras pessoas não são de confiança
skill.fromSomeoneElse({
  trust: 'none',
  risk: 'stolen secrets | hidden behaviour'
})

// O Centurion não instalará
// a skill de um estranho apenas pela sua palavra.

developers.code2:
centurion.makeSkill({
  for: 'what you actually need',
  basedOn: 'your life's mission',
  author: 'your Centurion'
})

// Cria skills. Não vai
// comprá-las numa loja.

developers.code3:
work.continues({
  gap: 'found',
  skill: 'made now',
  stays: 'with you'
})

// As skills surgem quando são necessárias —
// e ficam em sua casa, sob o seu controlo.

developers.code4:
loop.run({
  notice: true,
  act: true,
  learn: true,
  improve: true
})

// Reparar. Agir. Aprender. Melhorar.
// As skills melhoram com o uso —
// sem reportar para fora.

